// SearchReplaceTool.cs — Core library for recursive multi-file search and replace.
// Provides: glob-based file matching, regex search with context, preview mode,
// backup creation, and a summary report of all changes.

using System.Text.RegularExpressions;
using Microsoft.Extensions.FileSystemGlobbing;
using Microsoft.Extensions.FileSystemGlobbing.Abstractions;

/// <summary>
/// Represents a single match found during a search operation.
/// </summary>
public record SearchMatch(
    string FilePath,
    int LineNumber,
    string LineText,
    string MatchedText,
    int MatchStart,
    int MatchLength);

/// <summary>
/// Represents one replacement that was (or would be) made.
/// </summary>
public record ReplacementRecord(
    string FilePath,
    int LineNumber,
    string OldText,
    string NewText);

/// <summary>
/// Summary report produced after a search-and-replace operation.
/// </summary>
public record SummaryReport(
    int FilesSearched,
    int FilesMatched,
    int TotalMatches,
    int TotalReplacements,
    IReadOnlyList<ReplacementRecord> Replacements);

/// <summary>
/// Options controlling the behaviour of the search-and-replace tool.
/// </summary>
public class SearchReplaceOptions
