                    FilePath: filePath,
                    LineNumber: i + 1,
                    OldText: m.Value,
                    NewText: regex.Replace(m.Value, replacement)));
            }

            var replaced = regex.Replace(lines[i], replacement);
            if (replaced != lines[i])
            {
                lines[i] = replaced;
                modified = true;
            }
        }

        // Only write back if something changed
        if (modified)
        {
