        var matcher = new Matcher();
        matcher.AddInclude(globPattern);
        var result = matcher.Execute(new DirectoryInfoWrapper(new DirectoryInfo(rootDirectory)));
        return result.Files
            .Select(f => Path.GetFullPath(Path.Combine(rootDirectory, f.Path)))
            .OrderBy(p => p).ToList();
